module RefModule(
    clk,
    resetn,
    start_enable,
    start_time,
    timer
);parameter WIDTH = 10;

  input clk;
  input resetn;
  input start_enable;
  input [WIDTH-1:0] start_time;
  output [WIDTH-1:0] timer;

  reg [WIDTH-1:0] obf_counter;

  assign timer = obf_counter;

  always @(posedge clk) begin
  if (!resetn)
    obf_counter <= 0;
  else if( start_enable )
    obf_counter <= start_time;
  else if( obf_counter > 0 )
    obf_counter <= obf_counter - 1'b1;
end

endmodule
